import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjInputDate } from "./OjInputDate";
export { OjInputDate };

/**
 * Create an instance of [[OjInputDate]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojInputDate(driver, By.id('my-oj-input-date'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojInputDate(driver: DriverLike, by: By): Promise<OjInputDate> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjInputDate
  if (!(webEl instanceof OjInputDate)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-input-date>`);
  }
  return webEl;
}

register("oj-input-date", OjInputDate);
